def generation_config(thinking):
    if thinking:
        return {"temperature": 0.6, "top_p": 0.95, "max_new_tokens": 512}
    return {"temperature": 0.7, "top_p": 0.8, "max_new_tokens": 256}

think = generation_config(True)
fast = generation_config(False)
assert think == {"temperature": 0.6, "top_p": 0.95, "max_new_tokens": 512}, "Thinking mode: 0.6 / 0.95 / 512"
assert fast == {"temperature": 0.7, "top_p": 0.8, "max_new_tokens": 256}, "Fast chat: 0.7 / 0.8 / 256"
assert think["max_new_tokens"] > fast["max_new_tokens"], "Thinking mode needs room for <think> reasoning tokens"
assert think["temperature"] < fast["temperature"], "Thinking mode samples slightly cooler"
print("All sampling config tests passed!")
